package main

import (
	"errors"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON response with preview data
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

// getText extracts all text content from an HTML node subtree, trimming whitespace
func getText(n *html.Node) string {
	var text strings.Builder
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.TextNode {
			text.WriteString(n.Data)
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(n)
	return strings.TrimSpace(text.String())
}

// extractPreview parses an HTML document tree to extract page title and meta description
func extractPreview(n *html.Node) (title, description string) {
	if n.Type == html.ElementNode {
		switch n.Data {
		case "title":
			title = getText(n)
		case "meta":
			var name, content string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name":
					name = attr.Val
				case "content":
					content = attr.Val
				}
			}
			if strings.EqualFold(name, "description") {
				description = strings.TrimSpace(content)
			}
		}
	}

	// Traverse children only until both fields are found for efficiency
	for c := n.FirstChild; c != nil && (title == "" || description == ""); c = c.NextSibling {
		childTitle, childDesc := extractPreview(c)
		if title == "" {
			title = childTitle
		}
		if description == "" {
			description = childDesc
		}
	}

	return title, description
}

// FetchURLPreview is the echo handler for POST /preview endpoint
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request body: expected JSON with 'url' field",
		})
	}

	// Validate URL presence
	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid URL format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL must use HTTP or HTTPS scheme",
		})
	}

	// Create HTTP client with mandatory 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create GET request with propagated context
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("failed to create request: %v", err),
		})
	}

	// Set realistic User-Agent to avoid being blocked by default server configurations
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewFetcher/1.0)")

	// Execute the HTTP request
	resp, err := client.Do(httpReq)
	if err != nil {
		var urlErr *url.Error
		if errors.As(err, &urlErr) && urlErr.Timeout() {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{
				"error": "request to URL timed out after 3 seconds",
			})
		}
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Limit response body to 1MB to prevent abuse from large file downloads
	limitedBody := io.LimitReader(resp.Body, 1<<20)

	// Parse HTML content
	doc, err := html.Parse(limitedBody)
	if err != nil {
		return ctx.JSON(http.StatusUnprocessableEntity, map[string]string{
			"error": "failed to parse HTML content from URL",
		})
	}

	// Extract preview metadata
	title, description := extractPreview(doc)

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Add standard middleware for logging and panic recovery
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

