// getText recursively extracts all text content from an HTML node
func getText(n *html.Node) string {
	var text strings.Builder
	var traverse func(*html.Node)

	traverse = func(node *html.Node) {
		if node.Type == html.TextNode {
			text.WriteString(node.Data)
		}
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(n)
	return strings.TrimSpace(text.String())
}

// extractPreview parses HTML content to extract page title and meta description
func extractPreview(content io.Reader) (string, string, error) {
	doc, err := html.Parse(content)
	if err != nil {
		return "", "", fmt.Errorf("HTML parse failed: %w", err)
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(node *html.Node) {
		// Look for the <head> element
		if node.Type == html.ElementNode && node.Data == "head" {
			// Process all children of the head element
			for child := node.FirstChild; child != nil; child = child.NextSibling {
