func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Restrict to HTTP/HTTPS schemes only
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Initialize HTTP client with 3-second timeout to prevent hanging requests
	client := &http.Client{Timeout: 3 * time.Second}

	// Create GET request with proper User-Agent header
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to prepare request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to connect to the provided URL"})
	}
	defer resp.Body.Close()

	// Validate successful response status (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned non-success status code: %d", resp.StatusCode)})
	}

	// Verify response is HTML (case-insensitive check for MIME type)
	contentType := strings.ToLower(resp.Header.Get("Content-Type"))
	if!strings.HasPrefix(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Provided URL does not return HTML content"})
