// extractTitleAndDescription parses HTML to extract the <title> text and <meta name="description"> content
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	// Parse HTML into a node tree (handles malformed HTML gracefully)
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err!= nil {
		return "", ""
	}

	var (
		title       string
		description string
	)

	// Helper to extract all text content from a node (handles nested text nodes)
	getTextContent := func(n *html.Node) string {
		var textBuf strings.Builder
		var traverseText func(*html.Node)

		traverseText = func(node *html.Node) {
			if node.Type == html.TextNode {
				textBuf.WriteString(node.Data)
			}
			// Recurse through all child nodes
			for child := node.FirstChild; child!= nil; child = child.NextSibling {
				traverseText(child)
			}
		}

		traverseText(n)
		return strings.TrimSpace(textBuf.String())
	}

	// Traverse the full HTML node tree
	var traverse func(*html.Node)
	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode {
			// Extract title from <title> tag inside <head>
			if node.Data == "title" && node.Parent!= nil && node.Parent.Data == "head" {
				title = getTextContent(node)
			}

