			if node.Data == "meta" && node.Parent!= nil && node.Parent.Data == "head" {
				var metaName, metaContent string
				for _, attr := range node.Attr {
					// Case-insensitive check for "name" attribute
					if strings.EqualFold(attr.Key, "name") {
						metaName = attr.Val
					}
					if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				// Case-insensitive match for "description" meta name
				if strings.EqualFold(metaName, "description") {
					description = strings.TrimSpace(metaContent)
				}
			}
		}

		// Recurse through child nodes
		for child := node.FirstChild; child!= nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Initialize Echo framework instance
	e := echo.New()

	// Register the preview handler for POST requests at /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
