func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL with 3-second timeout
	client := &http.Client{Timeout: 3 * time.Second}
	reqHTTP, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check if upstream returned a successful status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Upstream returned HTTP %d", resp.StatusCode)})
	}

	// Verify the response is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Read up to 1MB of the response to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title string
	var description string
	reader := strings.NewReader(string(htmlContent))
	tokenizer := html.NewTokenizer(reader)

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of input or parsing error, return collected data
			return title, description

		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttributes := tokenizer.TagName()
			switch string(tagName) {
			case "title":
				// Collect all text content inside the title tag
				var titleBuf strings.Builder
				for {
					tt := tokenizer.Next()
					switch tt {
					case html.TextToken:
						titleBuf.Write(tokenizer.Text())
					case html.EndTagToken:
						endTagName, _ := tokenizer.TagName()
						if string(endTagName) == "title" {
							title = strings.TrimSpace(titleBuf.String())
						}
					case html.ErrorToken:
						// Premature end of document
						title = strings.TrimSpace(titleBuf.String())
						return title, description
					}
					// Exit loop if we found the closing title tag
					if tt == html.EndTagToken {
						tn, _ := tokenizer.TagName()
						if string(tn) == "title" {
							break
						}
					}
				}

			case "meta":
				if hasAttributes {
					var metaName, metaContent string
					for {
						attrKey, attrVal, moreAttr := tokenizer.TagAttr()
						switch string(attrKey) {
						case "name":
							metaName = strings.ToLower(string(attrVal))
						case "content":
							metaContent = string(attrVal)
						}
						if !moreAttr {
							break
						}
					}
					if metaName == "description" {
						description = strings.TrimSpace(metaContent)
					}
				}

			case "body":
				// No need to parse beyond the head section
				return title, description
			}

		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			if string(tagName) == "head" {
