func customDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Restrict to standard HTTP/HTTPS ports only
	if port != "80" && port != "443" {
		return nil, errors.New("disallowed port")
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Block access to private, loopback and link-local IP ranges
	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return nil, errors.New("disallowed IP address")
		}
	}

	// Dial the first reachable validated IP to prevent DNS rebinding
	var conn net.Conn
	var dialErr error
	dialer := &net.Dialer{}
	for _, ip := range ips {
		ipAddr := net.JoinHostPort(ip.String(), port)
		conn, dialErr = dialer.DialContext(ctx, network, ipAddr)
		if dialErr == nil {
			return conn, nil
		}
	}

	return nil, dialErr
}

// getTextContent extracts all text content from a node and its descendants
func getTextContent(n *html.Node) string {
	var text strings.Builder
	var traverse func(*html.Node)
	traverse = func(node *html.Node) {
		if node == nil {
			return
		}
		if node.Type == html.TextNode {
			text.WriteString(node.Data)
		}
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(n)
	return strings.TrimSpace(text.String())
}

// extractTitleAndDescription parses HTML to extract page title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var (
		title       string
		description string
		inHead      bool
		done        bool // Stop parsing after processing head section
	)

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if done || n == nil {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "head":
				inHead = true
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					traverse(c)
				}
				inHead = false
				done = true // No need to process body content
				return
			case "title":
				if inHead {
					title = getTextContent(n)
				}
			case "meta":
				if inHead {
					var name, content string
					for _, attr := range n.Attr {
						key := strings.ToLower(attr.Key)
						if key == "name" {
							name = strings.ToLower(attr.Val)
						} else if key == "content" {
							content = attr.Val
						}
					}
					if name == "description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate required URL field
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Parse and validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Validate allowed schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Validate allowed ports
	port := parsedURL.Port()
	if port != "" {
		if (parsedURL.Scheme == "http" && port != "80") || (parsedURL.Scheme == "https" && port != "443") {
			return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only ports 80 (HTTP) and 443 (HTTPS) are allowed"})
		}
	}

	// Configure HTTP client with SSRF protection
	transport := &http.Transport{
		DialContext: customDialContext,
	}

	client := &http.Client{
		Timeout: 3 * time.Second, // Prevent hanging requests
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirect count to prevent redirect loops
			if len(via) >= 10 {
				return errors.New("too many redirects")
			}
			// Ensure redirects only use HTTP/HTTPS
			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return errors.New("redirect to non-HTTP/HTTPS URL is not allowed")
			}
			return nil
		},
	}

	// Create request with propagated context for cancellation
	reqHTTP, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(reqHTTP)
	if err != nil {
		// Return generic error to avoid leaking internal implementation details
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Validate successful response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned status code %d", resp.StatusCode)})
	}

	// Validate response is HTML content
	ct, _, err := mime.ParseMediaType(resp.Header.Get("Content-Type"))
	if err != nil || ct != "text/html" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Read limited response body to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract metadata from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	// Register the handler at /preview path as required
	e.POST("/preview", FetchURLPreview)
	// Start server on port 8080 (adjust as needed for your environment)
	e.Logger.Fatal(e.Start(":8080"))
}

