func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	// Bind incoming JSON request body to the request struct
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request format: " + err.Error(),
		})
	}

	// Validate URL field is not empty
	trimmedURL := strings.TrimSpace(req.URL)
	if trimmedURL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required and cannot be empty",
		})
	}

	// Initialize HTTP client with 3-second timeout as required
	httpClient := http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch content from the provided URL
	resp, err := httpClient.Get(trimmedURL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "failed to retrieve URL content: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Verify response is HTML content
	contentType := strings.ToLower(resp.Header.Get("Content-Type"))
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "target URL does not return HTML content (received Content-Type: " + contentType + ")",
		})
	}

	// Parse HTML document
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "failed to parse HTML content: " + err.Error(),
		})
	}

	// Extract and clean page title (returns empty string if title tag not found)
	title := strings.TrimSpace(doc.Find("head title").Text())

	// Extract meta description content (returns empty string if tag/attribute not found)
	description, _ := doc.Find("meta[name='description']").Attr("content")
	description = strings.TrimSpace(description)

	// Return successful JSON response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

