	// Initialize Echo framework instance
	e := echo.New()

	// Register the /preview POST endpoint with the handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080 (fatal log on server failure)
	e.Logger.Fatal(e.Start(":8080"))
}

