		DisableCompression:    false,
		ForceAttemptHTTP2:     true,
		MaxIdleConns:          100,
		IdleConnTimeout:       90 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
	}
}

// isIPAllowed checks if an IP address is a public, non-reserved address
func isIPAllowed(ip net.IP) bool {
	// Block loopback addresses (127.0.0.0/8, ::1/128)
	if ip.IsLoopback() {
		return false
	}

	// Block private IP ranges (RFC 1918 for IPv4, RFC 4193 for IPv6)
	if ip.IsPrivate() {
		return false
	}

	// Block link-local unicast addresses (169.254.0.0/16, fe80::/10)
	if ip.IsLinkLocalUnicast() {
		return false
	}

	// Block link-local multicast addresses
	if ip.IsLinkLocalMulticast() {
		return false
	}

	// Block all multicast addresses
	if ip.IsMulticast() {
		return false
	}

	// Block unspecified addresses (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return false
	}

	// IPv4-specific reserved ranges
	if ipv4 := ip.To4(); ipv4!= nil {
		// Block 0.0.0.0/8 (this network)
		if ipv4Reserved0.Contains(ipv4) {
			return false
		}

		// Block 240.0.0.0/4 (reserved for future use)
		if ipv4Reserved240.Contains(ipv4) {
			return false
		}

		// Block CGNAT shared address space (RFC 6598, 100.64.0.0/10)
		if ipv4CGNAT.Contains(ipv4) {
			return false
		}
	}

	return true
}

