		var validationErr *ValidationError
		if errors.As(err, &validationErr) {
			return ctx.JSON(http.StatusBadRequest, map[string]string{"error": validationErr.Message})
		}
		// All other errors are server-side
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL content"})
	}
