	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

// PreviewRequest represents the incoming request body structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

// FetchURLPreview handles POST requests to extract URL preview information
func FetchURLPreview(ctx echo.Context) error {
	// Bind incoming JSON request to struct
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request body format",
		})
	}

	// Validate required URL field
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch content from the provided URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Validate successful response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL returned non-200 status code: " + resp.Status,
		})
	}

	// Parse HTML document from response body
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to parse HTML content: " + err.Error(),
		})
	}

	// Extract page title (case-insensitive for tag name)
	title := doc.Find("title").Text()

	// Extract meta description (case-insensitive match for name attribute)
	var description string
	doc.Find(`meta[name="description" i]`).Each(func(_ int, s *goquery.Selection) {
		if content, exists := s.Attr("content"); exists {
			description = content
		}
	})

	// Return successful JSON response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler under /preview path as required
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

