package main

import (
	"errors"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// HTTP client with 3-second timeout as required
var httpClient = &http.Client{
	Timeout: 3 * time.Second,
}

// FetchURLPreview handles POST requests to extract page title and meta description from a given URL
func FetchURLPreview(ctx echo.Context) error {
	// Bind request body to struct
	var req struct {
		URL string `json:"url"`
	}
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request body: expected JSON with 'url' field",
		})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Parse and validate URL scheme (only allow http/https)
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid URL format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL scheme must be http or https",
		})
	}

	// Fetch the target URL
	resp, err := httpClient.Get(req.URL)
	if err != nil {
		// Handle timeout specifically
		var netErr net.Error
		if errors.As(err, &netErr) && netErr.Timeout() {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{
				"error": "request to provided URL timed out after 3 seconds",
			})
		}
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate upstream response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusUnprocessableEntity, map[string]string{
			"error": fmt.Sprintf("upstream server returned non-success status: %s", resp.Status),
		})
	}

	// Validate content type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusUnprocessableEntity, map[string]string{
			"error": "provided URL does not return HTML content",
		})
	}

	// Parse HTML document
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusUnprocessableEntity, map[string]string{
			"error": "failed to parse HTML content",
		})
	}

	// Extract and clean title
	title := strings.TrimSpace(doc.Find("title").Text())

	// Extract and clean meta description (case-insensitive match for name attribute)
	description, _ := doc.Find("meta[name='description' i]").Attr("content")
	description = strings.TrimSpace(description)

	// Return successful response
	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Add common middleware
	e.Use(middleware.Logger())  // Log requests
	e.Use(middleware.Recover()) // Recover from panics

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

